 1	import * as React from 'react';
 2	import { Chip } from '@patternfly/react-core';
 3	import { kialiStyle } from 'styles/StyleUtils';
 4	import { MATCHING_SELECTED_TOOLTIP, wizardTooltip } from '../WizardHelp';
 5	import { t } from 'utils/I18nUtils';
 6	
 7	type Props = {
 8	  matches: string[];
 9	  onRemoveMatch: (match: string) => void;
10	};
11	
12	const labelContainerStyle = kialiStyle({
13	  marginTop: 20,
14	  height: 40
15	});
16	
17	const remove = kialiStyle({
18	  cursor: 'not-allowed'
19	});
20	
21	export class Matches extends React.Component<Props> {
22	  render() {
23	    const matches: any[] = this.props.matches.map((match, index) => (
24	      <span key={match + '-' + index} data-test={match} className={remove}>
25	        <Chip onClick={() => this.props.onRemoveMatch(match)} isOverflowChip={true}>
26	          {match}
27	        </Chip>{' '}
28	      </span>
29	    ));
30	    return (
31	      <div className={labelContainerStyle}>
32	        <span
33	          style={{
34	            marginRight: '32px'
35	          }}
36	        >
37	          {t('Matching selected')}
38	          {wizardTooltip(MATCHING_SELECTED_TOOLTIP)}
39	        </span>
40	        {matches.length > 0 ? matches : <b>{t('Match any request')}</b>}
41	      </div>
42	    );
43	  }
44	}

